package kotlinx.coroutines.future

import kotlinx.coroutines.*
import org.junit.Test
import java.util.concurrent.*
import kotlin.test.*

/**
 * Tests that verify `future` builder does not trigger global exception handler,
 * and delivers all errors via the returned CompletableFuture.
 */
class FutureExceptionHandlerTest : TestBase() {

    @Test
    fun testExceptionNotDeliveredToGlobalHandler() = runTest {
        // future builder should not trigger global exception handler
        // All errors should be delivered via the CompletableFuture
        val future = GlobalScope.future {
            throw TestException("FAIL")
        }

        // Wait for the future to complete
        delay(100)

        // Verify the future contains the exception
        assertTrue(future.isCompletedExceptionally)
        val exception = assertFailsWith<ExecutionException> {
            future.get()
        }
        assertTrue(exception.cause is TestException)
        assertEquals("FAIL", exception.cause?.message)
    }

    @Test
    fun testExceptionWithExternalCancellation() = runTest {
        // Test the scenario from the issue:
        // future throws an error, then is cancelled externally
        val future = GlobalScope.future {
            error("foo")
        }

        // Cancel the future externally
        future.cancel(true)

        // Wait a bit to ensure any exception handling is triggered
        delay(100)

        // Verify the future is cancelled or completed exceptionally
        assertTrue(future.isDone)
        assertTrue(future.isCompletedExceptionally || future.isCancelled)
    }

    @Test
    fun testExceptionInChildCoroutine() = runTest(
        expected = { it is TestException } // exception propagates to parent with structured concurrency
    ) {
        // When a child coroutine throws, it should propagate to parent
        // but should not trigger global handler
        val future = future<Int>(Dispatchers.Unconfined) {
            launch {
                throw TestException("child failed")
            }
            delay(Long.MAX_VALUE)
        }

        // Wait for completion
        delay(100)

        // Verify the future contains the exception
        assertTrue(future.isCompletedExceptionally)
        val exception = assertFailsWith<ExecutionException> {
            future.get()
        }
        assertTrue(exception.cause is TestException)
    }

    @Test
    fun testCancellationDoesNotTriggerHandler() = runTest {
        // Simple cancellation should not trigger exception handler
        val started = CompletableDeferred<Unit>()
        val future = GlobalScope.future {
            started.complete(Unit)
            delay(Long.MAX_VALUE)
        }

        // Wait for coroutine to start
        started.await()

        // Cancel the future
        future.cancel(true)

        // Wait a bit
        delay(100)

        // Verify it's cancelled
        assertTrue(future.isCancelled)
    }

    @Test
    fun testExceptionInFinallyBlock() = runTest {
        // Test that exception in finally block after external cancellation
        // doesn't trigger global handler
        val future = GlobalScope.future {
            try {
                delay(Long.MAX_VALUE)
            } finally {
                throw TestException("finally block")
            }
        }

        // Cancel externally
        future.cancel(true)

        // Wait a bit
        delay(100)

        // The future should be completed (either cancelled or with exception)
        assertTrue(future.isDone)
    }

    @Test
    fun testMultipleExternalCancellations() = runTest {
        // Test multiple cancellations don't cause issues
        val future = GlobalScope.future {
            try {
                delay(Long.MAX_VALUE)
            } catch (e: CancellationException) {
                // Rethrow cancellation
                throw e
            }
        }

        // Cancel multiple times
        future.cancel(true)
        future.cancel(true)

        // Wait a bit
        delay(100)

        // Should be cancelled
        assertTrue(future.isCancelled)
    }

    @Test
    fun testRaceConditionExceptionAndCancellation() = runTest {
        // Test rapid succession of exception and cancellation
        repeat(100) {
            val future = GlobalScope.future {
                // Sometimes this will throw before cancel, sometimes after
                delay(1)
                throw TestException("race")
            }

            // Cancel immediately
            future.cancel(true)

            // Wait for completion
            while (!future.isDone) {
                delay(1)
            }

            // Should be done (either cancelled or exceptionally completed)
            assertTrue(future.isDone)
        }
    }
}
