import kotlinx.coroutines.future.future
import java.util.concurrent.*

fun main() {
    println("Testing the fix for future() exception handler issue...")

    // Install a global exception handler to detect if it's triggered
    var globalHandlerTriggered = false
    val originalHandler = Thread.getDefaultUncaughtExceptionHandler()
    Thread.setDefaultUncaughtExceptionHandler { t, e ->
        println("FAILURE: Global exception handler was triggered!")
        println("Exception in thread $t: $e")
        e.printStackTrace()
        globalHandlerTriggered = true
        originalHandler?.uncaughtException(t, e)
    }

    try {
        // Test case 1: Exception in future
        println("\nTest 1: Exception in future")
        val future1 = GlobalScope.future {
            error("foo")
        }
        Thread.sleep(200)

        try {
            future1.get()
            println("ERROR: Should have thrown an exception")
        } catch (e: ExecutionException) {
            println("SUCCESS: Exception caught via future.get(): ${e.cause?.message}")
        }

        // Test case 2: Exception with external cancellation (original issue scenario)
        println("\nTest 2: Exception with external cancellation")
        val future2 = GlobalScope.future {
            error("bar")
        }
        future2.cancel(true)
        Thread.sleep(200)

        println("SUCCESS: No global handler triggered after cancel")

        // Test case 3: Normal cancellation
        println("\nTest 3: Normal cancellation")
        val future3 = GlobalScope.future {
            delay(10000)
            "result"
        }
        Thread.sleep(50)
        future3.cancel(true)
        Thread.sleep(100)

        try {
            future3.get()
            println("ERROR: Should have been cancelled")
        } catch (e: CancellationException) {
            println("SUCCESS: Future was cancelled as expected")
        }

        // Final check
        Thread.sleep(200)
        if (globalHandlerTriggered) {
            println("\n❌ FAILURE: Global exception handler was triggered (should not happen)")
            System.exit(1)
        } else {
            println("\n✅ SUCCESS: All tests passed, global handler was never triggered")
        }

    } finally {
        Thread.setDefaultUncaughtExceptionHandler(originalHandler)
    }
}
"}

