package kotlinx.coroutines.future

import kotlinx.coroutines.*
import org.junit.Test
import java.util.concurrent.*

/**
 * Test for the issue where future() may trigger global exception handler on cancellation.
 * See: https://github.com/Kotlin/kotlinx.coroutines/issues/892
 * 
 * The expected behavior is that `future` coroutine builder delivers all errors via the 
 * returned CompletableFuture, just like `async`, and should never trigger the global 
 * exception handler.
 */
class FutureGlobalExceptionHandlerTest : TestBase() {

    /**
     * This is the exact scenario from the issue report.
     * The future throws an error, then is cancelled.
     * This should NOT trigger the global exception handler.
     */
    @Test
    fun testIssueScenario() = runTest {
        // No unhandled exceptions should be caught
        val future = GlobalScope.future {
            error("foo")
        }
        future.cancel(true)
        delay(100)

        // Verify the future is completed (either with exception or cancellation)
        assertTrue(future.isDone)
    }

    /**
     * Test that a simple exception in future is delivered via the future,
     * not the global handler.
     */
    @Test
    fun testSimpleException() = runTest {
        val future = GlobalScope.future {
            throw TestException("test")
        }

        delay(100)

        // Exception should be in the future
        assertTrue(future.isCompletedExceptionally)
        val exception = assertFailsWith<ExecutionException> {
            future.get()
        }
        assertTrue(exception.cause is TestException)
    }

    /**
     * Test that cancelling a running future doesn't trigger the global handler.
     */
    @Test
    fun testCancellation() = runTest {
        val started = CompletableDeferred<Unit>()
        val future = GlobalScope.future {
            started.complete(Unit)
            delay(10000)
        }

        started.await()
        future.cancel(true)
        delay(100)

        assertTrue(future.isCancelled)
    }

    /**
     * Test the behavior matches async: exception stored in result, not sent to handler.
     */
    @Test
    fun testBehaviorMatchesAsync() = runTest {
        // async behavior
        val deferred = GlobalScope.async {
            throw TestException("async error")
        }
        delay(100)
        assertTrue(deferred.isCompleted)
        assertFailsWith<TestException> { deferred.await() }

        // future should behave the same way
        val future = GlobalScope.future {
            throw TestException("future error")
        }
        delay(100)
        assertTrue(future.isDone)
        val exception = assertFailsWith<ExecutionException> {
            future.get()
        }
        assertTrue(exception.cause is TestException)
    }

    /**
     * Test that when future is already completed externally,
     * subsequent exceptions don't trigger the global handler.
     */
    @Test
    fun testExternalCompletionThenException() = runTest {
        val latch = CompletableDeferred<Unit>()
        val future = GlobalScope.future {
            latch.await()
            throw TestException("should not reach handler")
        }

        // Complete the future externally before the exception
        future.complete(Unit as Nothing?)
        latch.complete(Unit)

        delay(100)

        // Future should be completed with the external value
        assertTrue(future.isDone)
    }
}
"}

